var e=JSON.parse(`[{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"나는 늘 중요한 순간에 눈을 돌렸다.","JPN":"私はいつも重要な瞬間に目を背けてきた。","ENG":"I always turned away from important moments.","TWN":"我總是在關鍵時刻把目光投向別處。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"어머니에게 죽을 뻔했을 때도.","JPN":"お母様に殺されそうになった時も。","ENG":"When Mother nearly killed me.","TWN":"差點被母親殺死的時候。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"아버지가 비참한 몰골이 되어 나타났을 때도.","JPN":"お父様が悲惨な姿で現れた時も。","ENG":"When Father appeared with such a terrible look.","TWN":"父親以悲慘的樣貌出現的時候。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"에델을 버리고 영지에서 도망쳤을 때도.","JPN":"エデルを捨てて、領地から逃げた時も。","ENG":"Even when I abandoned Edel and fled from the estate.","TWN":"丟下艾瑟兒，從領地中逃出去的時候。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"자, 이 책들을 주의 깊게 살펴 보세요.","JPN":"さあ、これらの本を注意深く読んでください。","ENG":"Now, take a careful look at these books.","TWN":"來，請記得要好好留意一下這些書。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"한 권씩 읽으면 흥미 위주로 쓰여진 것 같지만, 사실은 아니랍니다.","JPN":"一冊ずつ読むと興味本位で書かれた本のように見えますが、実は違います。","ENG":"If you read them one by one, they might seem to have been written just for the fun of it.","TWN":"如果你一本一本地讀下去，可能會覺得這些書是基於興趣寫出來的，但事實並非如此。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"행간과 행간, 단어와 단어 사이에 은밀하게 숨겨진 지식들을 하나로 엮어 가다 보면......","JPN":"行間と行間、単語と単語の間に秘められた知識を繋ぎ合わせていくと……","ENG":"But by reading between the lines and sewing the fragments of knowledge, hidden between words back together...","TWN":"只要把隱藏在句子和句子之間，單字和單字之間的知識串聯在一起……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"진실된 세계를 엿볼 수 있는 시야를 얻게 되죠.","JPN":"真実の世界を見ることができるようになります。","ENG":"You'll be able to gain an insight deep enough to peek through the world of truth.","TWN":"就可以獲得窺見真正世界的視野。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"지금은 이해하기 어렵겠지만, 언젠가 알게 되는 날이 올 거예요.","JPN":"今は理解できなくても、いつかわかる時が来るはずです。","ENG":"You're too young to understand now, but you'll definitely get there in the future.","TWN":"雖然現在你還很難理解，但妳總有一天會懂的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……언니.","JPN":"……お姉さん。","ENG":"…Edel.","TWN":"……姊姊。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"이해가 잘 안 되시나요? 다시 한 번 가르쳐 드릴까요?","JPN":"理解できませんか？　もう一度教えてあげましょうか。","ENG":"Is it confusing? Do you want us to explain it again?","TWN":"不懂嗎？要再跟你講一遍嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사실은 나, 오늘 밤에 영지를 떠날 거예요.","JPN":"実は私、今夜領地を出ます。","ENG":"Actually, I am going to leave the estate tonight.","TWN":"其實，我今天晚上要離開領地了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"그래요……?","JPN":"そうですか……","ENG":"Is that so...?","TWN":"是嗎……？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"좋은 소식이네요. 영지 바깥에는 신기한 것도 흥미로운 것도 무척 많답니다.","JPN":"いい知らせですね。領地の外には不思議なものも、興味深いものもたくさんあります。","ENG":"That's good news! There are many odd and fascinating things to see outside of the estate.","TWN":"這是好消息啊。聽說領地外面有很多新奇、有趣的東西。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"무서워하지 않아도 괜찮아요. 마음껏 많은 것을 경험하고 와 주세요.","JPN":"怖がらなくてもいいですよ。思いっきりたくさん経験してきてください。","ENG":"You don't have to be afraid. Please go out and enjoy yourself to the fullest.","TWN":"你不用害怕。盡情地去體驗更多東西，然後再回來吧。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"언니는 슬프지 않아요? 다시 오지 않을지도 몰라요.","JPN":"お姉さんは悲しくないのですか？　二度と戻ってこないかもしれません。","ENG":"Does it not make you sad? I might never return.","TWN":"姊姊不傷心嗎？我說不定就不再回來了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"……아뇨. 슬프지 않아요.","JPN":"……いいえ。悲しくありませんよ。","ENG":"...Of course not. We are not sad.","TWN":"……不，不傷心。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"레지나 님은 다시 돌아와 주실 테니까요. 책장 너머로 저희를 바라봐 주셨던 그 때처럼.","JPN":"レジーナ様はまたお戻りになるはずですから。本棚越しに我々を見てくださったあの時のように。","ENG":"We know you'll return, Miss Regina. Just like that time when you used to gaze at us from beyond the bookcase.","TWN":"蕾佳娜會回來的，就像從書架那頭看著我們那時候一樣。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"기다리고 있을게요.","JPN":"お待ちしています。","ENG":"We'll be waiting.","TWN":"我們等你。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"괴물이…… 얼음처럼 부서졌어……","JPN":"怪物が……氷のように砕けた……","ENG":"The monster... It shattered like ice...","TWN":"怪物……像冰塊一樣碎掉了……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"저, 정말 해내셨어요. 굉장해요, 부학회장님.","JPN":"ほ、本当に成し遂げられたのですね。すごいです、副学会長様。","ENG":"Th-that was amazing, Ms. Vice President!","TWN":"你…你真的做到了。你好厲害，副學會長。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아니에요. 애초에 저를 죽일 의도가 없었으니까요.","JPN":"いいえ。そもそも私を殺す気はなかったのですから。","ENG":"No, it never wanted to kill me in the first place.","TWN":"不，因為它一開始就沒打算殺我。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"본질이 죄책감이라면, 제가 현실을 외면하지 않기를 바라고 나타났던 거겠죠.","JPN":"本質が罪責感なら、私が現実から目を背けないことを望んで現れたのでしょう。","ENG":"If it was a manifestation of guilt, it appeared so that I would not ignore reality.","TWN":"如果它的本質是我的罪惡感，那麼它應該是希望我不要逃避現實才出現的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신처럼요. 실키.","JPN":"あなたのように。シルキー。","ENG":"Just like you are, Sylkie.","TWN":"就像你一樣，思琪。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"네? 저처럼이라니요?","JPN":"はい？　私のように？","ENG":"Sorry? Like me?","TWN":"啊？什麼叫像我一樣？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"법학부장의 펜던트에 들어 있던 초상화는…….","JPN":"法学部長のペンダントに入っていた肖像画は……","ENG":"The portrait I saw inside Dean of Law's pedant...","TWN":"法學院院長墜飾裡的畫像……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신의 것이었어요.","JPN":"あなたのものでした。","ENG":"It was you.","TWN":"是你的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L38_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"1408호에서 본 서신은 제가 쓴 것이 맞아요.","JPN":"1408号で見た手紙は、確かに私のものです。","ENG":"The letter I saw in room 1408, it was written by me.","TWN":"在1408號看的書信是我寫的沒錯。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"불길한 징후를 느끼고 나서, 만약의 상황에 대비하기 위한 조치였겠죠.","JPN":"不吉な前兆を感じてから、万一の状況に備えるためにそうしたのでしょう。","ENG":"I must have written it as a precaution after sensing a foreboding sign.","TWN":"應該是我感覺到不祥之兆後，為了以防萬一而採取的措施吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그림자에게 감시자를 요구한 까닭도……. 피해를 줄이기 위해서였을 겁니다.","JPN":"シャドウに監視役を頼んだのも……被害を減らすためだったはずです。","ENG":"And requesting a Shadow to be the supervisor... It was to minimize the damage.","TWN":"之所以讓暗影當監視者……也是為了減少損失。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런 상황에서 제가 간병인을 두고 지냈을까요?","JPN":"そのような状況下で、果たして私が看病人を置くでしょうか？","ENG":"But then, why would I have hired a caregiver?","TWN":"在那種情況下，我會留個看護嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"시설에 있던 학회원들도 처음 보는 듯한 반응이었죠.","JPN":"施設にいた学会員も初めて見るような反応でした。","ENG":"The Society members at the facility reacted as if it was their first time seeing you.","TWN":"設施裡的學會成員也都流露出了仿佛第一次看見你的反應。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"결국 실키, 당신도 제가 만들어낸 허상에 불과해요.","JPN":"つまりシルキー、あなたも私が作り出した虚像に過ぎません。","ENG":"After all, Sylkie, you are a figment of my imagination.","TWN":"所以，思琪，你也不過是我製造出來的幻影。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"저…… 부학회장님, 이걸 받아 주실 수 있을까요?","JPN":"あの……副学会長様、これを受け取ってください。","ENG":"Um... ma'am? I want you to have this.","TWN":"那個……副學會長，你能收下這個嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_GIRL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네? 이 바구니를요...?","JPN":"うん？　このカゴは……？","ENG":"Hmm? A basket?","TWN":"嗯？這個籃子嗎……？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"오우, 열매가 가득 들어 있네? 레지나한테 주려고 따 왔나 봐.","JPN":"うわ、木の実がいっぱいだね。レジーナにあげたくて摘んできたんじゃない？","ENG":"Ooh, it's got fruit inside it. I guess she went and picked them for you.","TWN":"哇喔，裡面裝滿了果實呢？好像是為了送給蕾佳娜才摘的。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"네. 달여 먹으면 감기에 좋다고 어른 분들께서 알려 주셨어요.","JPN":"はい。煎じて飲めば風邪によく効くと教わりました。","ENG":"Yes. The elders told me that it's good for treating colds if you brew them into medicine.","TWN":"是的。長輩們說過用這個熬點水喝下去，感冒比較快好。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"부학회장님께서 늘 추위로 고생하신다는 얘기를 들었거든요.","JPN":"副学会長様がいつも冷えで苦労されていると聞いて。","ENG":"I heard that you always suffer from the cold, ma'am.","TWN":"我聽說副學會長一直很怕冷。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"고마워요. 제가 영지에 돌아와서 받은 최고의 선물이에요.","JPN":"ありがとう。私が領地に戻ってから貰ったものの内で最高のプレゼントですわ。","ENG":"Thank you. This is the best gift I have ever received after coming back to the estate.","TWN":"謝謝你。這是我回到領地後，收到的最好的禮物。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"죄책감이 아니라……. 저 자신이 틀리지 않았길 바라던 마음이 만들어낸.","JPN":"罪責感ではなく……私自身が間違っていないことを願う心が作り出した。","ENG":"But you were not my guilt... You were hope, the hope that I was not wrong.","TWN":"不是罪惡感……而是我希望自己沒有錯的心意，製造出來的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"……네. 맞아요.","JPN":"……はい、そうです。","ENG":"...Yes, you're right.","TWN":"……是的，沒錯。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"역시 저랑 다르게 똑똑하시네요.","JPN":"やっぱり私とは違って、頭がいいですね。","ENG":"You really are smart, unlike me.","TWN":"和我不同，你果然很聰明。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"의외로… 순순히 인정하시는군요.","JPN":"意外と……素直に認めるのですね。","ENG":"I did not think... you would readily admit to it.","TWN":"我很意外……你居然乖乖地承認了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"저는 부학회장님이 바라셔서 나타났으니까요.","JPN":"私は副学会長様が望んで現れた存在ですから。","ENG":"I am only here because you wished for me.","TWN":"因為我是在副學會長的希望中出現的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"필요하셨죠? 자기 말에 귀기울여 주고, 힘들 때 돌봐 주고.","JPN":"必要だったでしょう？　自分の言葉を聞いてくれて、辛い時には世話をしてくれて。","ENG":"You needed me, right? You needed someone who would listen to you and take care of you.","TWN":"你是需要的吧？一個會傾聽你說話，在你辛苦時照顧你，"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"괴로우면 도망쳐도 된다고 해 줄 아이가요.","JPN":"辛かったら逃げていいと言ってくれる子が。","ENG":"Someone who would tell you it was okay to run if you were in pain.","TWN":"在你孤單時告訴你逃跑也沒關係的人。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그리고 이제는, 그런 아이가 더 필요없으시잖아요?","JPN":"そして今は、その存在はもう必要ありませんよね？","ENG":"But now, you don't need me anymore, do you?","TWN":"還有現在，你不再需要那樣的人了不是嘛？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"사탕은, 조금 아쉽지만요.","JPN":"キャンディーは、ちょっと残念ですけど。","ENG":"I think I'll miss not having candy anymore, but...","TWN":"就是，沒吃到糖果有點可惜。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"미안해요. 저 때문에 목숨을 버리게 해서.","JPN":"すみません。私のせいで命を捨てることになってしまって。","ENG":"I'm sorry... for making you give up your life like this.","TWN":"對不起，我害你丟掉了性命。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"절대로… 이 일은 절대로 잊지 않을게요.","JPN":"絶対……このことは、絶対忘れませんわ。","ENG":"I will... I will never forget you.","TWN":"這件事……我絕對不會忘記這件事。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"아뇨. 저희는 진심으로 부학회장님이 살아나시길 바랐어요.","JPN":"いいえ。私たちは本当に副学会長様が蘇ることを望んでいました。","ENG":"No. We sincerely hoped that you would live on.","TWN":"不，我們都是真心希望副學會長可以活下去的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"자원했다는 학회장님의 말은, 거짓말이 아니에요.","JPN":"志願したっていう学会長の言葉は、嘘じゃありません。","ENG":"The President wasn't lying when she said that we volunteered.","TWN":"學會長說我們都是自願的，這句話沒有騙人。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"다른 분을 살리기 위해서였다면 다들 망설였을 거예요.","JPN":"他の方を生かすためだったら、みんな迷ったはずです。","ENG":"If it were for anyone else, we might've hesitated.","TWN":"如果說為了救其他人，大家可能還會猶豫。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MAN_NPC_ESPR2_B","face":"UNIT_IDLE"},"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAN_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님이니까, 다들 조금이나마 보탬이 되려고 했던 거예요.","JPN":"副学会長様だから、みんな少しでもお役に立とうとしたんです。","ENG":"But because it's you... We all wanted to be helpful.","TWN":"但因為是副學會長，所以大家都想盡一份力。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MAN_NPC_ESPR2_B","face":"UNIT_IDLE"},"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAN_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"제단에 섰을 때는 다리가 조금 떨리긴 했지만…….","JPN":"祭壇に立った時には、足が少し震えましたけど……","ENG":"When I stood at the altar, I did tremble a bit...","TWN":"雖然站在祭壇上的時候，我的兩條腿確實有點發抖……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MAN_NPC_ESPR2_B","face":"UNIT_IDLE"},"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAN_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"모두가 호수를 찾고 계실 때도, 부학회장님은 저희를 생각해 주셨으니까요.","JPN":"皆さんが湖を探している時にも、副学会長様は私たちのことを思ってくださいました。","ENG":"But when everyone else was looking for the Lake, you were the only one to think about us.","TWN":"因為在所有人都忙著尋找湖水的時候，只有副學會長會替我們著想。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님, 우시는 거 아니죠?","JPN":"副学会長様、泣いてないですよね？","ENG":"You're not crying right now, are you Ms. Vice President?","TWN":"副學會長，你沒有哭吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저는…….","JPN":"私は……","ENG":"I...","TWN":"我……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저는, 울지 않아요. 정말로.","JPN":"私は、泣きません。本当に。","ENG":"I am not. Crying.","TWN":"我，不會哭的，真的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"……그래요. 다행이다.","JPN":"……そうですか。よかった。","ENG":"...I'm so relieved.","TWN":"……是嗎，那就好。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"이젠 닦아 드릴 수 없을 테니까요.","JPN":"もう拭ってさしあげられませんから。","ENG":"I won't be able to wipe off your tears anymore.","TWN":"因為我不能再幫你擦眼淚了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"포기하지 마세요, 부학회장님.","JPN":"諦めないでください、副学会長様。","ENG":"Don't give up, Ms. Vice President.","TWN":"請不要放棄，副學會長。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};